20	#include "kernel/register.h"
21	#include "kernel/log.h"
22	#include <stdlib.h>
23	#include <stdio.h>
24	
25	USING_YOSYS_NAMESPACE
26	PRIVATE_NAMESPACE_BEGIN
27	
28	struct FsmPass : public Pass {
29		FsmPass() : Pass("fsm", "extract and optimize finite state machines") { }
30		void help() override
31		{
32			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
33			log("\n");
34			log("    fsm [options] [selection]\n");
35			log("\n");
36			log("This pass calls all the other fsm_* passes in a useful order. This performs\n");
37			log("FSM extraction and optimization. It also calls opt_clean as needed:\n");
38			log("\n");
39			log("    fsm_detect          unless got option -nodetect\n");
40			log("    fsm_extract\n");
41			log("\n");
42			log("    fsm_opt\n");
43			log("    opt_clean\n");
44			log("    fsm_opt\n");
45			log("\n");
46			log("    fsm_expand          if got option -expand\n");
47			log("    opt_clean           if got option -expand\n");
48			log("    fsm_opt             if got option -expand\n");
49			log("\n");
50			log("    fsm_recode          unless got option -norecode\n");
51			log("\n");
52			log("    fsm_info\n");
53			log("\n");
54			log("    fsm_export          if got option -export\n");
55			log("    fsm_map             unless got option -nomap\n");
56			log("\n");
57			log("Options:\n");
58			log("\n");
59			log("    -expand, -norecode, -export, -nomap\n");
60			log("        enable or disable passes as indicated above\n");
61			log("\n");
62			log("    -fullexpand\n");
63			log("        call expand with -full option\n");
64			log("\n");
65			log("    -encoding type\n");
66			log("    -fm_set_fsm_file file\n");
67			log("    -encfile file\n");
68			log("        passed through to fsm_recode pass\n");
69			log("\n");
70			log("This pass uses a subset of FF types to detect FSMs. Run 'opt -nosdff -nodffe'\n");
71			log("before this pass to prepare the design.\n");
72			log("\n");
73	#ifdef YOSYS_ENABLE_VERIFIC
74			log("The Verific frontend may merge multiplexers in a way that interferes with FSM\n");
75			log("detection. Run 'verific -cfg db_infer_wide_muxes_post_elaboration 0' before\n");
76			log("reading the source, and 'bmuxmap' after 'proc' for best results.\n");
77			log("\n");
78	#endif
79		}
80		void execute(std::vector<std::string> args, RTLIL::Design *design) override
81		{
82			bool flag_nomap = false;
83			bool flag_norecode = false;
84			bool flag_nodetect = false;
85			bool flag_expand = false;
86			bool flag_fullexpand = false;
87			bool flag_export = false;
88			std::string fm_set_fsm_file_opt;
89			std::string encfile_opt;
90			std::string encoding_opt;
91	
92			log_header(design, "Executing FSM pass (extract and optimize FSM).\n");
93			log_push();
94	
95			size_t argidx;
96			for (argidx = 1; argidx < args.size(); argidx++) {
97				std::string arg = args[argidx];
98				if (arg == "-fm_set_fsm_file" && argidx+1 < args.size() && fm_set_fsm_file_opt.empty()) {
99					fm_set_fsm_file_opt = " -fm_set_fsm_file " + args[++argidx];
100					continue;
101				}
102				if (arg == "-encfile" && argidx+1 < args.size() && encfile_opt.empty()) {
103					encfile_opt = " -encfile " + args[++argidx];
104					continue;
105				}
106				if (arg == "-encoding" && argidx+1 < args.size() && encoding_opt.empty()) {
107					encoding_opt = " -encoding " + args[++argidx];
108					continue;
109				}
110				if (arg == "-nodetect") {
111					flag_nodetect = true;
112					continue;
113				}
114				if (arg == "-norecode") {
115					flag_norecode = true;
116					continue;
117				}
118				if (arg == "-nomap") {
119					flag_nomap = true;
120					continue;
121				}
122				if (arg == "-expand") {
123					flag_expand = true;
124					continue;
125				}
126				if (arg == "-fullexpand") {
127					flag_fullexpand = true;
128					continue;
129				}
130				if (arg == "-export") {
131					flag_export = true;
132					continue;
133				}
134				break;
135			}
136			extra_args(args, argidx, design);
137	
138			if (!flag_nodetect)
139				Pass::call(design, "fsm_detect");
140			Pass::call(design, "fsm_extract");
141	
142			Pass::call(design, "fsm_opt");
143			Pass::call(design, "opt_clean");
144			Pass::call(design, "fsm_opt");
145	
146			if (flag_expand || flag_fullexpand) {
147				Pass::call(design, flag_fullexpand ? "fsm_expand -full" : "fsm_expand");
148				Pass::call(design, "opt_clean");
149				Pass::call(design, "fsm_opt");
150			}
151	
152			if (!flag_norecode)
153				Pass::call(design, "fsm_recode" + fm_set_fsm_file_opt + encfile_opt + encoding_opt);
154			Pass::call(design, "fsm_info");
155	
156			if (flag_export)
157				Pass::call(design, "fsm_export");
158	
159			if (!flag_nomap)
160				Pass::call(design, "fsm_map");
161	
162			log_pop();
163		}
164	} FsmPass;
165	
166	PRIVATE_NAMESPACE_END
