27	
28	USING_YOSYS_NAMESPACE
29	PRIVATE_NAMESPACE_BEGIN
30	
31	struct FsmOpt
32	{
33		FsmData fsm_data;
34		RTLIL::Cell *cell;
35		RTLIL::Module *module;
36	
37		void opt_unreachable_states()
38		{
39			while (1)
40			{
41				std::set<int> unreachable_states;
42				std::vector<FsmData::transition_t> new_transition_table;
43				std::vector<RTLIL::Const> new_state_table;
44				std::map<int, int> old_to_new_state;
45	
46				for (int i = 0; i < GetSize(fsm_data.state_table); i++)
47					if (i != fsm_data.reset_state)
48						unreachable_states.insert(i);
49	
50				for (auto &trans : fsm_data.transition_table)
51					unreachable_states.erase(trans.state_out);
52	
53				if (unreachable_states.empty())
54					break;
55	
56				for (int i = 0; i < GetSize(fsm_data.state_table); i++) {
57					if (unreachable_states.count(i)) {
58						log("  Removing unreachable state %s.\n", log_signal(fsm_data.state_table[i]));
59						continue;
60					}
61					old_to_new_state[i] = GetSize(new_state_table);
62					new_state_table.push_back(fsm_data.state_table[i]);
63				}
64	
65				for (auto trans : fsm_data.transition_table) {
66					if (unreachable_states.count(trans.state_in))
67						continue;
68					trans.state_in = old_to_new_state.at(trans.state_in);
69					trans.state_out = old_to_new_state.at(trans.state_out);
70					new_transition_table.push_back(trans);
71				}
72	
73				new_transition_table.swap(fsm_data.transition_table);
74				new_state_table.swap(fsm_data.state_table);
75				if (fsm_data.reset_state != -1)
76					fsm_data.reset_state = old_to_new_state.at(fsm_data.reset_state);
77			}
78		}
79	
80		bool signal_is_unused(RTLIL::SigSpec sig)
81		{
82			RTLIL::SigBit bit = sig.as_bit();
83	
84			if (bit.wire == NULL || bit.wire->attributes.count(ID::unused_bits) == 0)
85				return false;
86	
87			char *str = strdup(bit.wire->attributes[ID::unused_bits].decode_string().c_str());
88			for (char *tok = strtok(str, " "); tok != NULL; tok = strtok(NULL, " ")) {
89				if (tok[0] && bit.offset == atoi(tok)) {
90					free(str);
91					return true;
92				}
93			}
94			free(str);
95	
96			return false;
97		}
98	
99		void opt_const_and_unused_inputs()
100		{
101			RTLIL::SigSpec ctrl_in = cell->getPort(ID::CTRL_IN);
102			std::vector<bool> ctrl_in_used(ctrl_in.size());
103	
104			std::vector<FsmData::transition_t> new_transition_table;
105			for (auto &tr : fsm_data.transition_table) {
106				for (int i = 0; i < ctrl_in.size(); i++) {
107					RTLIL::SigSpec ctrl_bit = ctrl_in.extract(i, 1);
108					if (ctrl_bit.is_fully_const()) {
109						if (tr.ctrl_in[i] <= RTLIL::State::S1 && RTLIL::SigSpec(tr.ctrl_in[i]) != ctrl_bit)
110							goto delete_this_transition;
111						continue;
112					}
113					if (tr.ctrl_in[i] <= RTLIL::State::S1)
114						ctrl_in_used[i] = true;
115				}
116				new_transition_table.push_back(tr);
117			delete_this_transition:;
118			}
119	
120			for (int i = int(ctrl_in_used.size())-1; i >= 0; i--) {
121				if (!ctrl_in_used[i]) {
122					log("  Removing unused input signal %s.\n", log_signal(cell->getPort(ID::CTRL_IN).extract(i, 1)));
123					for (auto &tr : new_transition_table) {
124						RTLIL::SigSpec tmp(tr.ctrl_in);
125						tmp.remove(i, 1);
126						tr.ctrl_in = tmp.as_const();
127					}
128					RTLIL::SigSpec new_ctrl_in = cell->getPort(ID::CTRL_IN);
129					new_ctrl_in.remove(i, 1);
130					cell->setPort(ID::CTRL_IN, new_ctrl_in);
131					fsm_data.num_inputs--;
132				}
133			}
134	
135			fsm_data.transition_table.swap(new_transition_table);
136			new_transition_table.clear();
137		}
138	
139		void opt_unused_outputs()
140		{
141			for (int i = 0; i < fsm_data.num_outputs; i++) {
142				RTLIL::SigSpec sig = cell->getPort(ID::CTRL_OUT).extract(i, 1);
143				if (signal_is_unused(sig)) {
144					log("  Removing unused output signal %s.\n", log_signal(sig));
145					RTLIL::SigSpec new_ctrl_out = cell->getPort(ID::CTRL_OUT);
146					new_ctrl_out.remove(i, 1);
147					cell->setPort(ID::CTRL_OUT, new_ctrl_out);
148					for (auto &tr : fsm_data.transition_table) {
149						RTLIL::SigSpec tmp(tr.ctrl_out);
150						tmp.remove(i, 1);
151						tr.ctrl_out = tmp.as_const();
152					}
153					fsm_data.num_outputs--;
154					i--;
155				}
156			}
157		}
158	
159		void opt_alias_inputs()
160		{
161			RTLIL::SigSpec &ctrl_in = cell->connections_[ID::CTRL_IN];
162	
163			for (int i = 0; i < ctrl_in.size(); i++)
164			for (int j = i+1; j < ctrl_in.size(); j++)
165				if (ctrl_in.extract(i, 1) == ctrl_in.extract(j, 1))
166				{
167					log("  Optimize handling of signal %s that is connected to inputs %d and %d.\n", log_signal(ctrl_in.extract(i, 1)), i, j);
168					std::vector<FsmData::transition_t> new_transition_table;
169	
170					for (auto tr : fsm_data.transition_table)
171					{
172						RTLIL::State si = tr.ctrl_in[i];
173						RTLIL::State sj = tr.ctrl_in[j];
174	
175						if (si > RTLIL::State::S1) {
176							si = sj;
177							tr.ctrl_in.set(i, si);
178						} else if (sj > RTLIL::State::S1) {
179							sj = si;
180							tr.ctrl_in.set(j, sj);
181						}
182	
183						if (si == sj) {
184							RTLIL::SigSpec tmp(tr.ctrl_in);
185							tmp.remove(j, 1);
186							tr.ctrl_in = tmp.as_const();
187							new_transition_table.push_back(tr);
188						}
189					}
190	
191					ctrl_in.remove(j--, 1);
192					fsm_data.num_inputs--;
193	
194					fsm_data.transition_table.swap(new_transition_table);
195					new_transition_table.clear();
196				}
197		}
198	
199		void opt_feedback_inputs()
200		{
201			RTLIL::SigSpec &ctrl_in = cell->connections_[ID::CTRL_IN];
202			RTLIL::SigSpec &ctrl_out = cell->connections_[ID::CTRL_OUT];
203	
204			for (int j = 0; j < ctrl_out.size(); j++)
205			for (int i = 0; i < ctrl_in.size(); i++)
206				if (ctrl_in.extract(i, 1) == ctrl_out.extract(j, 1))
207				{
208					log("  Optimize handling of signal %s that is connected to input %d and output %d.\n", log_signal(ctrl_in.extract(i, 1)), i, j);
209					std::vector<FsmData::transition_t> new_transition_table;
210	
211					for (auto tr : fsm_data.transition_table)
212					{
213						RTLIL::State si = tr.ctrl_in[i];
214						RTLIL::State sj = tr.ctrl_out[j];
215	
216						if (si > RTLIL::State::S1 || si == sj) {
217							RTLIL::SigSpec tmp(tr.ctrl_in);
218							tmp.remove(i, 1);
219							tr.ctrl_in = tmp.as_const();
220							new_transition_table.push_back(tr);
221						}
222					}
223	
224					ctrl_in.remove(i--, 1);
225					fsm_data.num_inputs--;
226	
227					fsm_data.transition_table.swap(new_transition_table);
228					new_transition_table.clear();
229				}
230		}
231	
232		void opt_find_dont_care_worker(std::set<RTLIL::Const> &set, int bit, FsmData::transition_t &tr, bool &did_something)
233		{
234			std::set<RTLIL::Const> new_set;
235	
236			for (auto &pattern : set)
237			{
238				if (pattern[bit] > RTLIL::State::S1) {
239					new_set.insert(pattern);
240					continue;
241				}
242	
243				RTLIL::Const other_pattern = pattern;
244	
245				if (pattern[bit] == RTLIL::State::S1)
246					other_pattern.set(bit, RTLIL::State::S0);
247				else
248					other_pattern.set(bit, RTLIL::State::S1);
249	
250				if (set.count(other_pattern) > 0) {
251					log("  Merging pattern %s and %s from group (%d %d %s).\n", log_signal(pattern), log_signal(other_pattern),
252							tr.state_in, tr.state_out, log_signal(tr.ctrl_out));
253					other_pattern.set(bit, RTLIL::State::Sa);
254					new_set.insert(other_pattern);
255					did_something = true;
256					continue;
257				}
258	
259				new_set.insert(pattern);
260			}
261	
262			set.swap(new_set);
263		}
264	
265		void opt_find_dont_care()
266		{
267			typedef std::pair<std::pair<int, int>, RTLIL::Const> group_t;
268			std::map<group_t, std::set<RTLIL::Const>> transitions_by_group;
269	
270			for (auto &tr : fsm_data.transition_table) {
271				group_t group(std::pair<int, int>(tr.state_in, tr.state_out), tr.ctrl_out);
272				transitions_by_group[group].insert(tr.ctrl_in);
273			}
274	
275			fsm_data.transition_table.clear();
276			for (auto &it : transitions_by_group)
277			{
278				FsmData::transition_t tr;
279				tr.state_in = it.first.first.first;
280				tr.state_out = it.first.first.second;
281				tr.ctrl_out = it.first.second;
282	
283				bool did_something = true;
284				while (did_something) {
285					did_something = false;
286					for (int i = 0; i < fsm_data.num_inputs; i++)
287						opt_find_dont_care_worker(it.second, i, tr, did_something);
288				}
289	
290				for (auto &ci : it.second) {
291					tr.ctrl_in = ci;
292					fsm_data.transition_table.push_back(tr);
293				}
294			}
295		}
296	
297		FsmOpt(RTLIL::Cell *cell, RTLIL::Module *module)
298		{
299			log("Optimizing FSM `%s' from module `%s'.\n", cell->name, module->name);
300	
301			fsm_data.copy_from_cell(cell);
302			this->cell = cell;
303			this->module = module;
304	
305			opt_unreachable_states();
306	
307			opt_unused_outputs();
308	
309			opt_alias_inputs();
310			opt_feedback_inputs();
311			opt_find_dont_care();
312	
313			opt_const_and_unused_inputs();
314	
315			fsm_data.copy_to_cell(cell);
316		}
317	};
318	
319	PRIVATE_NAMESPACE_END
320	
321	void YOSYS_NAMESPACE_PREFIX FsmData::optimize_fsm(RTLIL::Cell *cell, RTLIL::Module *module)
322	{
323		FsmOpt fsmopt(cell, module);
324	}
325	
326	PRIVATE_NAMESPACE_BEGIN
327	
328	struct FsmOptPass : public Pass {
329		FsmOptPass() : Pass("fsm_opt", "optimize finite state machines") { }
330		void help() override
331		{
332			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
333			log("\n");
334			log("    fsm_opt [selection]\n");
335			log("\n");
