45	// Concurrent queue implementation. Not fast, but simple.
46	// Multi-producer, multi-consumer, optionally bounded.
47	// When YOSYS_ENABLE_THREADS is not defined, this is just a non-thread-safe non-blocking deque.
48	template <typename T>
49	class ConcurrentQueue
50	{
51	public:
52		ConcurrentQueue(int capacity = INT_MAX)
53			: capacity(capacity) {}
54		// Push an element into the queue. If it's at capacity, block until there is room.
55		void push_back(T t)
56		{
57			UniqueLock lock(mutex);
58			not_full_condition.wait(lock, [this] { return static_cast<int>(contents.size()) < capacity; });
59			if (contents.empty())
60				not_empty_condition.notify_one();
61			log_assert(!closed);
62			contents.push_back(std::move(t));
63			if (static_cast<int>(contents.size()) < capacity)
64				not_full_condition.notify_one();
65		}
66		// Signal that no more elements will be produced. `pop_front()` will return nullopt.
67		void close()
68		{
69			UniqueLock lock(mutex);
70			not_empty_condition.notify_all();
71			closed = true;
72		}
73		// Pop an element from the queue. Blocks until an element is available
74		// or the queue is closed and empty.
75		std::optional<T> pop_front()
76		{
77			return pop_front_internal(true);
78		}
79		// Pop an element from the queue. Does not block, just returns nullopt if the
80		// queue is empty.
81		std::optional<T> try_pop_front()
82		{
83			return pop_front_internal(false);
84		}
85	private:
86		std::optional<T> pop_front_internal(bool wait)
87		{
88			UniqueLock lock(mutex);
89			if (wait) {
90				not_empty_condition.wait(lock, [this] { return !contents.empty() || closed; });
91			}
92			if (contents.empty())
93				return std::nullopt;
94			if (static_cast<int>(contents.size()) == capacity)
95				not_full_condition.notify_one();
96			T result = std::move(contents.front());
97			contents.pop_front();
98			if (!contents.empty())
99				not_empty_condition.notify_one();
100			return std::move(result);
101		}
102	
103		Mutex mutex;
104		// Signals one waiter thread when the queue changes and is not full.
105		CondVar not_full_condition;
106		// Signals one waiter thread when the queue changes and is not empty.
107		CondVar not_empty_condition;
108		std::deque<T> contents;
109		int capacity;
110		bool closed = false;
111	};
