136	class ThreadPool
137	{
138	public:
139		// Computes the number of worker threads to use.
140		// `reserved_cores` cores are set aside for other threads (e.g. work on the main thread).
141		// `max_worker_threads` --- don't return more workers than this.
142		// The result may be 0.
143		static int pool_size(int reserved_cores, int max_worker_threads);
144	
145		// Computes the number of worker threads to use, by dividing work_units among threads.
146		// For testing purposes you can set YOSYS_WORK_UNITS_PER_THREAD to override `work_units_per_thread`.
147		// The result may be 0.
148		static int work_pool_size(int reserved_cores, int work_units, int work_units_per_thread);
149	
150		// Create a pool of threads running the given closure (parameterized by thread number).
151		// `pool_size` must be the result of a `pool_size()` call.
152		ThreadPool(int pool_size, std::function<void(int)> b);
153		ThreadPool(ThreadPool &&other) = delete;
154		// Waits for all threads to terminate. Make sure those closures return!
155		~ThreadPool();
156	
157		// Return the number of threads in the pool.
158		int num_threads() const
159		{
160	#ifdef YOSYS_ENABLE_THREADS
161			return threads.size();
162	#else
163			return 0;
164	#endif
165		}
166	private:
167		std::function<void(int)> body;
168	#ifdef YOSYS_ENABLE_THREADS
169		std::vector<std::thread> threads;
170	#endif
171	};
172	
173	// Divides some number of items into `num_threads` subranges and returns the
174	// `thread_num`'th subrange. If `num_threads` is zero, returns the whole range.
175	IntRange item_range_for_worker(int num_items, int thread_num, int num_threads);
176	
177	// A type that encapsulates the index of a thread in some list of threads. Useful for
178	// stronger typechecking and code readability.
179	struct ThreadIndex {
180		int thread_num;
181	};
182	
183	// A set of threads with a `run()` API that runs a closure on all of the threads
184	// and wait for all those closures to complete. This is a convenient way to implement
185	// parallel algorithms that use barrier synchronization.
186	class ParallelDispatchThreadPool
187	{
188	public:
189		// Create a pool of threads running the given closure (parameterized by thread number).
190		// `pool_size` must be the result of a `pool_size()` call.
191		// `pool_size` can be zero, which we treat as 1.
192		ParallelDispatchThreadPool(int pool_size);
193		~ParallelDispatchThreadPool();
194	
195		// For each thread running a closure, a `RunCtx` is passed to the closure. Currently
196		// it contains the thread index and the total number of threads. It can be passed
197		// directly to any APIs requiring a `ThreadIndex`.
198		struct RunCtx : public ThreadIndex {
199			int num_threads;
200			IntRange item_range(int num_items) const {
201				return item_range_for_worker(num_items, thread_num, num_threads);
202			}
203		};
204		// Sometimes we only want to activate a subset of the threads in the pool. This
205		// class provides a way to do that. It provides the same `num_threads()`
206		// and `run()` APIs as a `ParallelDispatchThreadPool`.
207		class Subpool {
208		public:
209			Subpool(ParallelDispatchThreadPool &parent, int max_threads)
210					: parent(parent), max_threads(max_threads) {}
211			// Returns the number of threads that will be used when calling `run()`.
212			int num_threads() const {
213				return parent.num_threads(max_threads);
214			}
215			void run(std::function<void(const RunCtx &)> work) {
216				parent.run(std::move(work), max_threads);
217			}
218			ParallelDispatchThreadPool &thread_pool() { return parent; }
219		private:
220			ParallelDispatchThreadPool &parent;
221			int max_threads;
222		};
223	
224		// Run the `work` function in parallel on each thread in the pool (parameterized by
225		// thread number). Waits for all work functions to complete. Only one `run()` can be
226		// active at a time.
227		// Uses no more than `max_threads` threads (but at least one).
228		void run(std::function<void(const RunCtx &)> work) {
229			run(std::move(work), INT_MAX);
230		}
231	
232		// Returns the number of threads that will be used when calling `run()`.
233		int num_threads() const {
234			return num_threads(INT_MAX);
235		}
236	private:
237		friend class Subpool;
238	
239		void run(std::function<void(const RunCtx &)> work, int max_threads);
240		int num_threads(int max_threads) const {
241			return std::min(num_worker_threads_ + 1, std::max(1, max_threads));
242		}
243		void run_worker(int thread_num);
244	
245		std::function<void(const RunCtx &)> *current_work = nullptr;
246		// Keeps a correct count even when threads are exiting.
247		int num_worker_threads_;
248		// The count of active worker threads for the current `run()`.
249		// This is only written by the main thread, and only written when
250		// no other worker threads are running (i.e. all worker threads have
251		// passed the increment of `done_workers` in `signal_worker_done()`
252		// and not passed the release of the lock in `worker_wait_for_start()`.
253		// Although there can't be any races, we still need to make it atomic
254		// to prevent the compiler reordering accesses so the above invariant
255		// is maintained.
256		std::atomic<int> num_active_worker_threads_ = 0;
257	
258		// Not especially efficient for large numbers of threads. Worker wakeup could scale
259		// better by conceptually organising workers into a tree and having workers wake
260		// up their children.
261		Mutex main_to_workers_signal_mutex;
262		CondVar main_to_workers_signal_cv;
263		std::vector<uint8_t> main_to_workers_signal;
264		void signal_workers_start() {
265			UniqueLock lock(main_to_workers_signal_mutex);
266			int num_active_worker_threads = num_active_worker_threads_.load(std::memory_order_relaxed);
267			std::fill(main_to_workers_signal.begin(), main_to_workers_signal.begin() + num_active_worker_threads, 1);
268			// When `num_active_worker_threads_` is small compared to `num_worker_threads_`, we have a "thundering herd"
269			// problem here. Fixing that would add complexity so don't worry about it for now.
270			main_to_workers_signal_cv.notify_all();
271		}
272		void worker_wait_for_start(int thread_num) {
273			UniqueLock lock(main_to_workers_signal_mutex);
274			main_to_workers_signal_cv.wait(lock, [this, thread_num] { return main_to_workers_signal[thread_num] > 0; });
275			main_to_workers_signal[thread_num] = 0;
276		}
277	
278		std::atomic<int> done_workers = 0;
279		Mutex workers_to_main_signal_mutex;
280		CondVar workers_to_main_signal_cv;
281		void signal_worker_done() {
282			// Must read `num_active_worker_threads_` before we increment `d`! Otherwise
283			// it is possible we would increment `d`, and then another worker signals the
284			// main thread that all workers are done, and the main thread writes to
285			// `num_active_worker_threads_` before we check it.
286			int num_active_worker_threads = num_active_worker_threads_.load(std::memory_order_relaxed);
287			int d = done_workers.fetch_add(1, std::memory_order_release);
288			if (d + 1 == num_active_worker_threads) {
289				UniqueLock lock(workers_to_main_signal_mutex);
290				workers_to_main_signal_cv.notify_all();
291			}
292		}
293		void wait_for_workers_done() {
294			UniqueLock lock(workers_to_main_signal_mutex);
295			workers_to_main_signal_cv.wait(lock, [this] {
296				int num_active_worker_threads = num_active_worker_threads_.load(std::memory_order_relaxed);
297				return done_workers.load(std::memory_order_acquire) == num_active_worker_threads;
298			});
299			done_workers.store(0, std::memory_order_relaxed);
300		}
301		// Ensure `thread_pool` is destroyed before any other members,
302		// forcing all threads to be joined before destroying the
303		// members (e.g. workers_to_main_signal_mutex) they might be using.
304		std::unique_ptr<ThreadPool> thread_pool;
305	};
306	
307	template <class T>
308	class ConcurrentStack
309	{
310	public:
311		void push_back(T &&t) {
312			LockGuard lock(mutex);
313			contents.push_back(std::move(t));
314		}
315		std::optional<T> try_pop_back() {
316			LockGuard lock(mutex);
317			if (contents.empty())
318				return std::nullopt;
319			T result = std::move(contents.back());
320			contents.pop_back();
321			return result;
322		}
323	private:
324		Mutex mutex;
325		std::vector<T> contents;
326	};
327	
328	// A vector that is sharded into buckets, one per thread. This lets multiple threads write
329	// efficiently to the vector without synchronization overhead. After all writers have
330	// finished writing, the vector can be iterated over. The iteration order is deterministic:
331	// all the elements written by thread 0 in the order it inserted them, followed by all elements
332	// written by thread 1, etc.
333	template <typename T>
334	class ShardedVector {
335	public:
336		ShardedVector(const ParallelDispatchThreadPool &thread_pool) {
337			init(thread_pool.num_threads());
338		}
339		ShardedVector(const ParallelDispatchThreadPool::Subpool &thread_pool) {
340			init(thread_pool.num_threads());
341		}
342	
343		// Insert a value, passing the `ThreadIndex` of the writer thread.
344		// Parallel inserts with different `ThreadIndex` values are fine.
345		// Inserts must not run concurrently with any other methods (e.g.
346		// iteration or `empty()`.)
347		void insert(const ThreadIndex &thread, T value) {
348			buckets[thread.thread_num].emplace_back(std::move(value));
349		}
350	
351		bool empty() const {
352			for (const std::vector<T> &bucket : buckets)
353				if (!bucket.empty())
354					return false;
355			return true;
356		}
357	
358		using Buckets = std::vector<std::vector<T>>;
359		class iterator {
360		public:
361			iterator(typename Buckets::iterator bucket_it, typename Buckets::iterator bucket_end)
362				: bucket_it(std::move(bucket_it)), bucket_end(std::move(bucket_end)) {
363				if (bucket_it != bucket_end)
364					inner_it = bucket_it->begin();
365				normalize();
366			}
367			T& operator*() const { return *inner_it.value(); }
368			iterator &operator++() {
369				++*inner_it;
370				normalize();
371				return *this;
372			}
373			bool operator!=(const iterator &other) const {
374				return bucket_it != other.bucket_it || inner_it != other.inner_it;
375			}
376		private:
377			void normalize() {
378				if (bucket_it == bucket_end)
379					return;
380				while (inner_it == bucket_it->end()) {
381					++bucket_it;
382					if (bucket_it == bucket_end) {
383						inner_it.reset();
384						return;
385					}
386					inner_it = bucket_it->begin();
387				}
388			}
389			std::optional<typename std::vector<T>::iterator> inner_it;
390			typename Buckets::iterator bucket_it;
391			typename Buckets::iterator bucket_end;
392		};
393		iterator begin() { return iterator(buckets.begin(), buckets.end()); }
394		iterator end() { return iterator(buckets.end(), buckets.end()); }
395	private:
396		void init(int num_threads) {
397			buckets.resize(num_threads);
398		}
399		Buckets buckets;
400	};
401	
402	// This collision handler for `ShardedHashtable` resolves collisions by keeping
403	// the current value and discarding the other. This is correct when all values with the
404	// same key are interchangeable, i.e. when the hashtable is being used as a set instead
405	// of a map.
406	template <typename V>
407	struct SetCollisionHandler {
408		void operator()(typename V::Accumulated &, typename V::Accumulated &) const {}
409	};
410	
411	// A hashtable that can be efficiently built in parallel and then looked up concurrently.
412	// `V` is the type of elements that will be added to the hashtable. It must have a
413	// member type `Accumulated` representing the combination of multiple `V` elements. This
414	// can be the same as `V`, but for example `V` could contain a Wire* and `V::Accumulated`
415	// could contain a `pool<Wire*>`. `KeyEquality` is a class containing an `operator()` that
416	// returns true of two `V` elements have equal keys.
417	// `CollisionHandler` is used to reduce two `V::Accumulated` values into a single value.
418	//
419	// To use this, first construct a `Builder` and fill it in (in parallel), then construct
420	// a `ShardedHashtable` from the `Builder`.
421	template <typename V, typename KeyEquality, typename CollisionHandler>
422	class ShardedHashtable {
423	public:
424		// A combination of a `V` and its hash value.
425		struct Value {
426			Value(V value, unsigned int hash) : value(std::move(value)), hash(hash) {}
427			Value(Value &&) = default;
428			Value(const Value &) = delete;
429			Value &operator=(const Value &) = delete;
430			V value;
431			unsigned int hash;
432		};
433		// A combination of a `V::Accumulated` and its hash value.
434		struct AccumulatedValue {
435			AccumulatedValue(typename V::Accumulated value, unsigned int hash) : value(std::move(value)), hash(hash) {}
436			AccumulatedValue(AccumulatedValue &&) = default;
437	#if defined(_MSC_VER)
438			AccumulatedValue(const AccumulatedValue &) {
439				log_error("Copy constructor called on AccumulatedValue");
440			}
441			AccumulatedValue &operator=(const AccumulatedValue &) {
442				log_error("Copy assignment called on AccumulatedValue");
443				return *this;
444			}
445	#else
446			AccumulatedValue(const AccumulatedValue &) = delete;
447			AccumulatedValue &operator=(const AccumulatedValue &) = delete;
448	#endif
449			typename V::Accumulated value;
450			unsigned int hash;
451		};
452		// A class containing an `operator()` that returns true of two `AccumulatedValue`
453		// elements have equal keys.
454		// Required to insert `AccumulatedValue`s into an `std::unordered_set`.
455		struct AccumulatedValueEquality {
456			KeyEquality inner;
457			AccumulatedValueEquality(const KeyEquality &inner) : inner(inner) {}
458			bool operator()(const AccumulatedValue &v1, const AccumulatedValue &v2) const {
459				return inner(v1.value, v2.value);
460			}
461		};
462		// A class containing an `operator()` that returns the hash value of an `AccumulatedValue`.
463		// Required to insert `AccumulatedValue`s into an `std::unordered_set`.
464		struct AccumulatedValueHashOp {
465			size_t operator()(const AccumulatedValue &v) const {
466				return static_cast<size_t>(v.hash);
467			}
468		};
469		using Shard = std::unordered_set<AccumulatedValue, AccumulatedValueHashOp, AccumulatedValueEquality>;
470	
471		// First construct one of these. Then populate it in parallel by calling `insert()` from many threads.
472		// Then do another parallel phase calling `process()` from many threads.
473		class Builder {
474		public:
475			Builder(const ParallelDispatchThreadPool &thread_pool, KeyEquality equality = KeyEquality(), CollisionHandler collision_handler = CollisionHandler())
476					: collision_handler(std::move(collision_handler)) {
477				init(thread_pool.num_threads(), std::move(equality));
478			}
479			Builder(const ParallelDispatchThreadPool::Subpool &thread_pool, KeyEquality equality = KeyEquality(), CollisionHandler collision_handler = CollisionHandler())
480					: collision_handler(std::move(collision_handler)) {
481				init(thread_pool.num_threads(), std::move(equality));
482			}
483			// First call `insert` to insert all elements. All inserts must finish
484			// before calling any `process()`.
485			void insert(const ThreadIndex &thread, Value v) {
486				// You might think that for the single-threaded case, we can optimize by
487				// inserting directly into the `std::unordered_set` here. But that slows things down
488				// a lot and I never got around to figuring out why.
489				std::vector<std::vector<Value>> &buckets = all_buckets[thread.thread_num];
490				size_t bucket = static_cast<size_t>(v.hash) % buckets.size();
491				buckets[bucket].emplace_back(std::move(v));
492			}
493			// Then call `process` for each thread. All `process()`s must finish before using
494			// the `Builder` to construct a `ShardedHashtable`.
495			void process(const ThreadIndex &thread) {
496				int size = 0;
497				for (std::vector<std::vector<Value>> &buckets : all_buckets)
498					size += GetSize(buckets[thread.thread_num]);
499				Shard &shard = shards[thread.thread_num];
500				shard.reserve(size);
501				for (std::vector<std::vector<Value>> &buckets : all_buckets) {
502					for (Value &value : buckets[thread.thread_num])
503						accumulate(value, shard);
504					// Free as much memory as we can during the parallel phase.
505					std::vector<Value>().swap(buckets[thread.thread_num]);
506				}
507			}
508		private:
509			friend class ShardedHashtable<V, KeyEquality, CollisionHandler>;
510			void accumulate(Value &value, Shard &shard) {
511				// With C++20 we could make this more efficient using heterogenous lookup
512				AccumulatedValue accumulated_value{std::move(value.value), value.hash};
513				auto [it, inserted] = shard.insert(std::move(accumulated_value));
514				if (!inserted)
515					collision_handler(const_cast<typename V::Accumulated &>(it->value), accumulated_value.value);
516			}
517			void init(int num_threads, KeyEquality equality) {
518				all_buckets.resize(num_threads);
519				for (std::vector<std::vector<Value>> &buckets : all_buckets)
520					buckets.resize(num_threads);
521				for (int i = 0; i < num_threads; ++i)
522					shards.emplace_back(0, AccumulatedValueHashOp(), AccumulatedValueEquality(equality));
523			}
524			const CollisionHandler collision_handler;
525			// A num_threads x num_threads matrix of buckets.
526			// In the first phase, each thread i gemerates elements and writes them to
527			// bucket [i][j] where j = hash(element) % num_threads.
528			// In the second phase, thread i reads from bucket [j][i] for all j, collecting
529			// all elements where i = hash(element) % num_threads.
530			std::vector<std::vector<std::vector<Value>>> all_buckets;
531			std::vector<Shard> shards;
532		};
533	
534		// Then finally construct the hashtable:
535		ShardedHashtable(Builder &builder) : shards(std::move(builder.shards)) {
536			// Check that all necessary 'process()' calls were made.
537			for (std::vector<std::vector<Value>> &buckets : builder.all_buckets)
538				for (std::vector<Value> &bucket : buckets)
539					log_assert(bucket.empty());
540			// Free memory.
541			std::vector<std::vector<std::vector<Value>>>().swap(builder.all_buckets);
542		}
543		ShardedHashtable(ShardedHashtable &&other) = default;
544		ShardedHashtable() {}
545	
546		ShardedHashtable &operator=(ShardedHashtable &&other) = default;
547	
548		// Look up by `AccumulatedValue`. If we switch to C++20 then we could use
549		// heterogenous lookup to support looking up by `Value` here. Returns nullptr
550		// if the key is not found.
551		const typename V::Accumulated *find(const AccumulatedValue &v) const {
552			size_t num_shards = shards.size();
553			if (num_shards == 0)
554				return nullptr;
555			size_t shard = static_cast<size_t>(v.hash) % num_shards;
556			auto it = shards[shard].find(v);
557			if (it == shards[shard].end())
558				return nullptr;
559			return &it->value;
560		}
561	
562		// Insert an element into the table. The caller is responsible for ensuring this does not
563		// happen concurrently with any other method calls.
564		void insert(AccumulatedValue v) {
565			size_t num_shards = shards.size();
566			if (num_shards == 0)
567				return;
568			size_t shard = static_cast<size_t>(v.hash) % num_shards;
569			shards[shard].insert(v);
570		}
571	
572		// Call this for each shard to implement parallel destruction. For very large `ShardedHashtable`s,
573		// deleting all elements of all shards on a single thread can be a performance bottleneck.
574		void clear(const ThreadIndex &shard) {
575			AccumulatedValueEquality equality = shards[shard.thread_num].key_eq();
576			shards[shard.thread_num] = Shard(0, AccumulatedValueHashOp(), equality);
577		}
578	private:
579		std::vector<Shard> shards;
580	};
581	
582	// A concurrent work-queue that can share batches of work across threads.
583	// Uses a naive implementation of work-stealing.
584	template <typename T>
585	class ConcurrentWorkQueue {
586	public:
587		// Create a queue that supports the given number of threads and
588		// groups work into `batch_size` units.
589		ConcurrentWorkQueue(int num_threads, int batch_size = 100)
590			: batch_size(batch_size), thread_states(num_threads) {}
591		int num_threads() const { return GetSize(thread_states); }
592		// Push some work to do. Pushes and pops with the same `thread` must
593		// not happen concurrently.
594		void push(const ThreadIndex &thread, T work) {
595			ThreadState &thread_state = thread_states[thread.thread_num];
596			thread_state.next_batch.emplace_back(std::move(work));
597			if (GetSize(thread_state.next_batch) < batch_size)
598				return;
599			bool was_empty;
600			{
601				UniqueLock lock(thread_state.batches_lock);
602				was_empty = thread_state.batches.empty();
603				thread_state.batches.push_back(std::move(thread_state.next_batch));
604			}
605			if (was_empty) {
606				UniqueLock lock(waiters_lock);
607				if (num_waiters > 0) {
608					waiters_cv.notify_one();
609				}
610			}
611		}
612		// Grab some work to do.
613		// If all threads enter `pop_batch()`, then instead of deadlocking the
614		// queue will return no work. That is the only case in which it will
615		// return no work.
616		std::vector<T> pop_batch(const ThreadIndex &thread) {
617			ThreadState &thread_state = thread_states[thread.thread_num];
618			if (!thread_state.next_batch.empty())
619				return std::move(thread_state.next_batch);
620			// Empty our own work queue first.
621			{
622				UniqueLock lock(thread_state.batches_lock);
623				if (!thread_state.batches.empty()) {
624					std::vector<T> batch = std::move(thread_state.batches.back());
625					thread_state.batches.pop_back();
626					return batch;
627				}
628			}
629			// From here on in this function, our work queue is empty.
630			while (true) {
631				std::vector<T> batch = try_steal(thread);
632				if (!batch.empty()) {
633					return std::move(batch);
634				}
635				// Termination: if all threads run out of work, then all of
636				// them will eventually enter this loop and there will be no further
637				// notifications on waiters_cv, so all will eventually increment
638				// num_waiters and wait, so num_waiters == num_threads()
639				// will become true. In single-threaded builds, num_threads() is 1,
640				// so we always terminate on the first iteration.
641				UniqueLock lock(waiters_lock);
642				++num_waiters;
643				if (num_waiters == num_threads()) {
644					waiters_cv.notify_all();
645					return {};
646				}
647				// As above, it's possible that we'll wait here even when there
648				// are work batches posted by other threads. That's OK.
649				waiters_cv.wait(lock);
650				if (num_waiters == num_threads())
651					return {};
652				--num_waiters;
653			}
654		}
655	private:
656		std::vector<T> try_steal(const ThreadIndex &thread) {
657			for (int i = 1; i < num_threads(); i++) {
658				int other_thread_num = (thread.thread_num + i) % num_threads();
659				ThreadState &other_thread_state = thread_states[other_thread_num];
660				UniqueLock lock(other_thread_state.batches_lock);
661				if (!other_thread_state.batches.empty()) {
662					std::vector<T> batch = std::move(other_thread_state.batches.front());
663					other_thread_state.batches.pop_front();
664					return batch;
665				}
666			}
667			return {};
668		}
669	
670		int batch_size;
671	
672		struct ThreadState {
673			// Entirely thread-local.
674			std::vector<T> next_batch;
675	
676			Mutex batches_lock;
677			// Only the associated thread ever adds to this, and only at the back.
678			// Other threads can remove elements from the front.
679			std::deque<std::vector<T>> batches;
680		};
681		std::vector<ThreadState> thread_states;
682	
683		Mutex waiters_lock;
684		CondVar waiters_cv;
685		// Number of threads waiting for work. Their queues are empty.
686		int num_waiters = 0;
687	};
688	
689	// A monotonic flag. Starts false, and can be set to true in a thread-safe way.
690	// Once `load()` returns true, it will always return true.
691	// Uses relaxed atomics so there are no memory ordering guarantees. Do not use this
692	// to guard access to shared memory.
693	class MonotonicFlag {
694	public:
695		MonotonicFlag() : value(false) {}
696		bool load() const { return value.load(std::memory_order_relaxed); }
697		void set() { value.store(true, std::memory_order_relaxed); }
698		bool set_and_return_old() {
699			return value.exchange(true, std::memory_order_relaxed);
700		}
701	private:
702		std::atomic<bool> value;
703	};
704	
705	YOSYS_NAMESPACE_END
706	
707	#endif // YOSYS_THREADING_H
